    private fun initializeCardIndexFromOrdinal(note: Note, col: Collection) {
        val totalCards = note.numberOfCardsEphemeral()
        if (totalCards <= 0) {
            cardIndex = 0
            noteEditorCardIndexInitialized = true
            return
        }
        val safeOrdinal = mOrdinal.coerceAtLeast(0)
        val initialIndex = if (note.notetype.isCloze) {
            val clozeNumbers = col.clozeNumbersInNote(note)
            val target = safeOrdinal + 1
            val matchedIndex = clozeNumbers.indexOf(target)
            if (matchedIndex >= 0) matchedIndex else 0
        } else {
            safeOrdinal
        }
        cardIndex = initialIndex.coerceIn(0, totalCards - 1)
        noteEditorCardIndexInitialized = true
    }

    private fun clampCardIndexWithinBounds(note: Note) {
        val totalCards = note.numberOfCardsEphemeral()
        cardIndex = if (totalCards <= 0) {
            0
        } else {
            cardIndex.coerceIn(0, totalCards - 1)
        }
    }

